def fib(n):
    a, b = 1, 1
    for _ in range(2, n):
        a, b = b, a + b
    return b
print(fib(50) % 1000)

def prime_factorization(n):
    factors = []
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1:
        factors.append(n)
    return factors

n = 123456789
print(prime_factorization(n))
